INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (563, 164687, 13, 1128, '冬之恋', '月亮像顽童似的扬着发亮的脸斜挂在天边，它周围的云也像被点亮了似的，亮晶晶的换着身姿。四周暮色已暗，微风中夹着丝丝寒冬的惬意迎面而来。对这一切，我都似乎毫无感觉，只是无奈下漫不经心地沿着那条即熟悉又陌生的小路走着，走着，直到回想起不禁黯然泪下。在那个寒冬的夜晚，放眼望去，路显得越发漆黑，风过处，路旁大树的枝条频频点头，绿色的枝叶纷纷扬扬随风飘着，飘着，像空中变幻的云，像夜晚缥缈的梦，更像那远去的往事……
<br>    认识冬是在校园里，那时的她才刚上初一，灿烂的笑容里带着更多的是稚韧的天真。而我当时刚刚中考结束，闲来无事常回母校逛逛！说来也巧，当时是足球帮了忙。由于我天性好玩，玩得一脚球技，而她对足球分外喜爱，就如此简单而又合乎逻辑的，我们相识了！后来才知道她对我的文采早就佩服万分，对我关注已久！
<br>    往后，我们便经常通信，偶尔也通电话，不管在任何时候任何方面都相互切磋，互不相让，就这样我们成为好朋友，彼此之间都没想过会有进一步发展。直到有一天，一件事情的发生，改变了我和她的态度，也转换了我们的关系。也因为这件事的发生使我们从此以后陷入了苦海，不能自拔。
<br>    同样是在寒冬的一天，我们相约在学校门口见面。见面后，我们还是像平时一样满天胡侃，直到车站。可当时突然之间冒出一个男大学生，在她面前叽哩呱啦说个不停，她露出生气的样子。一旁的同学走来告诉我：这人下午欺负冬，并像冬搭讪。听了这话，也不知为何发火，朝着那男大学生就是打。冬在一旁哭着，并不停喊着让我别打。我当时不明白她为什么哭，但我心里却很清楚，我在不经意间爱上了她。当天晚上她打来电话，虽然我并没有直截了当表明爱意，但却暗示，她或许已经明白，约我隔天在学校附近的海边碰面。
<br>    第二天我如约前去海边，与她见面后变开始表达我的心意，经过一番深思熟虑后，她答应了我。往后的日子我们几乎天天见面，回家后通通电话，一次便不下1个小时。这其间，她也曾不止一次的提出分手，但都在被我拒绝后不了了之。说来奇怪，我们两人名字的比划都为20划，也是20，在我们相处20天后，她又提出分手，这次她格外坚持，也不知我是不是做错了什么，想必只有冬心里最清楚了。
<br>    在她执意离开我的晚上，她亲了我，我也吻了她，看得出她还是依旧爱我，可是……这是她第一次，同样也是我的第一次。
<br>    20个旭日东升，20次夕阳西下，我都忘情地徘徊在即熟悉又陌生的那条小路，寻找当初的足迹，领悟那曾经付出时的真诚。今日，重温旧梦，却已是形单影只，物是人非。我唯一想多说的是：冬，在爱的幸福国度，你就是我唯一，我唯一爱的就是你。我们彼此珍重。
<br>    轻轻地你走了，正如你轻轻地来；你轻轻地招手，作别西天的云彩。
<br>    悄悄地你走了，正如你悄悄地来；你挥挥衣袖，不带走一片云彩。', '月亮像顽童似的扬着发亮的脸斜挂在天边，它周围的云也像被点亮了似的，亮晶晶的换着身姿。四周暮色已暗，微风中夹着丝丝寒冬的惬意迎面而来。对这一切，我都似乎毫无感觉，只是无奈下漫不经心地沿着那条即熟悉又陌生的小路走着，走着，直到回想起不禁黯然泪下。在那个寒冬的夜晚，放眼望去，路显得越发漆黑，风过处，路旁大树的枝条频频点头，绿色的枝叶纷纷扬扬随风飘着，飘着，像空中变幻的云，像夜晚缥缈的梦，更像那远去的往事……

认识冬是在校园里，那时的她才刚上初一，灿烂的笑容里带着更多的是稚韧的天真。而我当时刚刚中考结束，闲来无事常回母校逛逛！说来也巧，当时是足球帮了忙。由于我天性好玩，玩得一脚球技，而她对足球分外喜爱，就如此简单而又合乎逻辑的，我们相识了！后来才知道她对我的文采早就佩服万分，对我关注已久！

往后，我们便经常通信，偶尔也通电话，不管在任何时候任何方面都相互切磋，互不相让，就这样我们成为好朋友，彼此之间都没想过会有进一步发展。直到有一天，一件事情的发生，改变了我和她的态度，也转换了我们的关系。也因为这件事的发生使我们从此以后陷入了苦海，不能自拔。

同样是在寒冬的一天，我们相约在学校门口见面。见面后，我们还是像平时一样满天胡侃，直到车站。可当时突然之间冒出一个男大学生，在她面前叽哩呱啦说个不停，她露出生气的样子。一旁的同学走来告诉我：这人下午欺负冬，并像冬搭讪。听了这话，也不知为何发火，朝着那男大学生就是打。冬在一旁哭着，并不停喊着让我别打。我当时不明白她为什么哭，但我心里却很清楚，我在不经意间爱上了她。当天晚上她打来电话，虽然我并没有直截了当表明爱意，但却暗示，她或许已经明白，约我隔天在学校附近的海边碰面。

第二天我如约前去海边，与她见面后变开始表达我的心意，经过一番深思熟虑后，她答应了我。往后的日子我们几乎天天见面，回家后通通电话，一次便不下1个小时。这其间，她也曾不止一次的提出分手，但都在被我拒绝后不了了之。说来奇怪，我们两人名字的比划都为20划，也是20，在我们相处20天后，她又提出分手，这次她格外坚持，也不知我是不是做错了什么，想必只有冬心里最清楚了。

在她执意离开我的晚上，她亲了我，我也吻了她，看得出她还是依旧爱我，可是……这是她第一次，同样也是我的第一次。

20个旭日东升，20次夕阳西下，我都忘情地徘徊在即熟悉又陌生的那条小路，寻找当初的足迹，领悟那曾经付出时的真诚。今日，重温旧梦，却已是形单影只，物是人非。我唯一想多说的是：冬，在爱的幸福国度，你就是我唯一，我唯一爱的就是你。我们彼此珍重。

轻轻地你走了，正如你轻轻地来；你轻轻地招手，作别西天的云彩。

悄悄地你走了，正如你悄悄地来；你挥挥衣袖，不带走一片云彩。', NULL, '2002-06-07 20:07:00', 2, '20020621104138_bbsid_164687_board_13_7a16f898a2.html', '20020621104138');
